function createRenderer() {
  function clamp(x) { return Math.max(0, Math.min(1, x)); }
  function easeOut(x) { x = clamp(x); return 1 - Math.pow(1 - x, 3); }
  function easeInOut(x) { x = clamp(x); return x < 0.5 ? 4 * x * x * x : 1 - Math.pow(-2 * x + 2, 3) / 2; }
  function rr(ctx, x, y, w, h, r) { ctx.beginPath(); ctx.moveTo(x+r,y); ctx.lineTo(x+w-r,y); ctx.quadraticCurveTo(x+w,y,x+w,y+r); ctx.lineTo(x+w,y+h-r); ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h); ctx.lineTo(x+r,y+h); ctx.quadraticCurveTo(x,y+h,x,y+h-r); ctx.lineTo(x,y+r); ctx.quadraticCurveTo(x,y,x+r,y); ctx.closePath(); }
  function hex(ctx, x, y, r) { ctx.beginPath(); for (var i=0;i<6;i++){ var a=Math.PI/6+i*Math.PI/3; var px=x+Math.cos(a)*r, py=y+Math.sin(a)*r; if(i===0)ctx.moveTo(px,py); else ctx.lineTo(px,py); } ctx.closePath(); }
  function render(t, context) {
    var ctx = context.mainContext;
    var W = context.width, H = context.height;
    var intro = easeOut(t / 1.2);
    var mid = easeInOut((t - 1.1) / 2.6);
    var stats = easeOut((t - 3.1) / 1.2);
    var finish = easeOut((t - 5.2) / 1.1);
    var bg = ctx.createLinearGradient(0, 0, W, H);
    bg.addColorStop(0, '#050914'); bg.addColorStop(0.5, '#0b1d34'); bg.addColorStop(1, '#111d16');
    ctx.fillStyle = bg; ctx.fillRect(0,0,W,H);

    ctx.save();
    ctx.globalAlpha = 0.14;
    ctx.strokeStyle = '#63e6ff'; ctx.lineWidth = 1;
    for (var x=-200; x<W+200; x+=72) { ctx.beginPath(); ctx.moveTo(x+(t*26)%72, 0); ctx.lineTo(x-280+(t*26)%72, H); ctx.stroke(); }
    for (var y=0; y<H; y+=72) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke(); }
    ctx.restore();

    ctx.save();
    var orb = 0.5 + 0.5 * Math.sin(t * 1.6);
    ctx.globalAlpha = 0.16;
    ctx.fillStyle = '#00d4ff'; ctx.beginPath(); ctx.arc(W*0.76, H*0.26, 310 + orb*42, 0, Math.PI*2); ctx.fill();
    ctx.fillStyle = '#f2aa4c'; ctx.beginPath(); ctx.arc(W*0.23, H*0.78, 260 + Math.cos(t*1.2)*34, 0, Math.PI*2); ctx.fill();
    ctx.restore();

    drawProduct(ctx, W, H, t, intro, mid);
    drawCopy(ctx, W, H, t, intro, finish);
    drawMetrics(ctx, W, H, t, stats);
    drawPipeline(ctx, W, H, t, finish);
    drawProgress(ctx, W, H, t);
  }

  function drawProduct(ctx, W, H, t, intro, mid) {
    var cx = W * 0.68 + (1-intro)*220;
    var cy = H * 0.52 - (1-intro)*80;
    ctx.save(); ctx.translate(cx, cy); ctx.rotate((-7 + Math.sin(t*.8)*1.5) * Math.PI / 180); ctx.scale(0.86 + mid*0.12, 0.86 + mid*0.12);
    ctx.globalAlpha = intro;
    ctx.shadowColor = 'rgba(0,0,0,.65)'; ctx.shadowBlur = 70; ctx.shadowOffsetY = 34;
    rr(ctx, -230, -360, 460, 720, 48); var shell=ctx.createLinearGradient(-230,-360,230,360); shell.addColorStop(0,'#f8fafc'); shell.addColorStop(.48,'#d7e3ef'); shell.addColorStop(1,'#9caec0'); ctx.fillStyle=shell; ctx.fill();
    ctx.shadowBlur = 0;
    rr(ctx, -180, -300, 360, 448, 34); var screen=ctx.createLinearGradient(-180,-300,180,148); screen.addColorStop(0,'#06111f'); screen.addColorStop(.5,'#0ea5e9'); screen.addColorStop(1,'#16a34a'); ctx.fillStyle=screen; ctx.fill();
    ctx.save(); ctx.clip(); ctx.globalAlpha=.35; ctx.strokeStyle='#fff'; for(var i=0;i<12;i++){ ctx.beginPath(); ctx.arc(0, -80, 50+i*28+t*8%28, 0, Math.PI*2); ctx.stroke(); } ctx.restore();
    ctx.fillStyle='#111827'; ctx.font='900 52px Arial'; ctx.textAlign='center'; ctx.fillText('UI2V',0,242);
    ctx.font='22px Arial'; ctx.fillStyle='#4b5563'; ctx.fillText('Browser Render System',0,280);
    ctx.fillStyle='#f2aa4c'; ctx.beginPath(); ctx.arc(0,322,24+Math.sin(t*4)*2,0,Math.PI*2); ctx.fill();
    ctx.restore();

    ctx.save(); ctx.globalAlpha = mid;
    var nodes = [[W*.58,H*.22,'JSON'],[W*.84,H*.28,'Canvas'],[W*.84,H*.70,'MP4'],[W*.54,H*.76,'Runtime']];
    ctx.strokeStyle='rgba(125,220,255,.38)'; ctx.lineWidth=2;
    for(var n=0;n<nodes.length;n++){ var a=nodes[n], b=nodes[(n+1)%nodes.length]; ctx.beginPath(); ctx.moveTo(a[0],a[1]); ctx.lineTo(b[0],b[1]); ctx.stroke(); }
    for(var j=0;j<nodes.length;j++){ var nd=nodes[j]; hex(ctx, nd[0], nd[1], 54+Math.sin(t*2+j)*5); ctx.fillStyle='rgba(4,14,28,.76)'; ctx.fill(); ctx.strokeStyle='#7bd88f'; ctx.stroke(); ctx.fillStyle='#dff6ff'; ctx.font='700 20px Arial'; ctx.textAlign='center'; ctx.textBaseline='middle'; ctx.fillText(nd[2], nd[0], nd[1]); }
    ctx.restore();
  }

  function drawCopy(ctx, W, H, t, intro, finish) {
    ctx.save(); ctx.globalAlpha = intro; ctx.textAlign='left';
    ctx.fillStyle='#ffffff'; ctx.font='900 86px Arial, sans-serif'; ctx.fillText('Ship motion', 120, 180); ctx.fillText('from code.', 120, 270);
    ctx.fillStyle='#a9bdd2'; ctx.font='28px Arial'; ctx.fillText('A launch-film style example rendered entirely from JSON and Canvas.', 124, 338); ctx.fillText('No video editor. No manual timeline. Just deterministic frames.', 124, 378);
    ctx.restore();
    ctx.save(); ctx.globalAlpha=finish; rr(ctx,120,846,286,66,14); ctx.fillStyle='#f2aa4c'; ctx.fill(); ctx.fillStyle='#111827'; ctx.font='900 22px Arial'; ctx.textAlign='center'; ctx.fillText('RENDER 1080P MP4',263,887);
    ctx.fillStyle='#d7e6f4'; ctx.textAlign='left'; ctx.font='22px Arial'; ctx.fillText('8 second high-resolution product showcase',432,887); ctx.restore();
  }

  function drawMetrics(ctx, W, H, t, p) {
    var labels=[['1920x1080','production canvas'],['30 FPS','frame plan'],['WebCodecs','MP4 pipeline']];
    for(var i=0;i<labels.length;i++){ var x=124+i*250, y=520+(1-p)*30; ctx.save(); ctx.globalAlpha=p; ctx.fillStyle='rgba(4,10,20,.68)'; ctx.strokeStyle=i===1?'#f2aa4c':'rgba(255,255,255,.18)'; ctx.lineWidth=1.5; rr(ctx,x,y,214,126,16); ctx.fill(); ctx.stroke(); ctx.fillStyle=i===1?'#f2aa4c':'#7bd88f'; ctx.font='900 27px Arial'; ctx.fillText(labels[i][0],x+24,y+48); ctx.fillStyle='#b8c8d8'; ctx.font='17px Arial'; ctx.fillText(labels[i][1],x+24,y+82); ctx.restore(); }
  }

  function drawPipeline(ctx, W, H, t, p) {
    var steps=['JSON','Runtime','Canvas','WebCodecs','MP4']; var x0=124,y=712;
    ctx.save(); ctx.globalAlpha=p; ctx.font='700 18px Arial'; ctx.textAlign='center';
    for(var i=0;i<steps.length;i++){ var x=x0+i*138; ctx.fillStyle='rgba(255,255,255,.10)'; rr(ctx,x-54,y-28,108,56,12); ctx.fill(); ctx.strokeStyle=i<4?'#00d4ff':'#f2aa4c'; ctx.stroke(); ctx.fillStyle='#eef6ff'; ctx.fillText(steps[i],x,y+5); if(i<steps.length-1){ ctx.strokeStyle='rgba(255,255,255,.35)'; ctx.beginPath(); ctx.moveTo(x+58,y); ctx.lineTo(x+80,y); ctx.stroke(); } }
    ctx.restore();
  }

  function drawProgress(ctx, W, H, t) { var p=clamp(t/8); ctx.fillStyle='rgba(255,255,255,.12)'; rr(ctx,120,H-72,W-240,12,6); ctx.fill(); var g=ctx.createLinearGradient(120,0,W-120,0); g.addColorStop(0,'#00d4ff'); g.addColorStop(1,'#f2aa4c'); ctx.fillStyle=g; rr(ctx,120,H-72,(W-240)*p,12,6); ctx.fill(); }
  return { render: render };
}
